/** Indices into a 32-char hex id; spreads samples across the digest before filling gaps */
const SPREAD_ORDER = [
  0, 8, 16, 24, 4, 12, 20, 28, 1, 9, 17, 25, 2, 10, 18, 26, 3, 11, 19, 27, 5, 13, 21, 29, 6,
  14, 22, 30, 7, 15, 23, 31,
];

/**
 * Shorten a hex event id using spread sampling: adds more digits as `length` increases.
 */
export function spreadHashChars(hexId: string, length: number): string {
  const take = Math.min(Math.max(length, 0), SPREAD_ORDER.length);
  if (hexId.length < 25) {
    return hexId.substring(0, Math.min(take, hexId.length));
  }
  let out = '';
  for (let i = 0; i < take; i++) {
    out += hexId[SPREAD_ORDER[i]];
  }
  return out;
}

/**
 * Smallest spread length ≥ 4 such that all ids map to distinct short hashes (max 32 chars).
 */
export function computeMinimalSpreadHashLength(hexIds: string[]): number {
  const uniqueIds = Array.from(new Set(hexIds));
  const maxLen = SPREAD_ORDER.length;
  for (let spreadLen = 4; spreadLen <= maxLen; spreadLen++) {
    const hashes = uniqueIds.map(id => spreadHashChars(id, spreadLen));
    if (new Set(hashes).size === uniqueIds.length) {
      return spreadLen;
    }
  }
  return maxLen;
}

/**
 * Generate a shortened hash using spread characters (default length 4: positions 0, 8, 16, 24).
 */
export function generateShortHash(input: string, spreadLength = 4): string {
  return spreadHashChars(input, spreadLength);
}
