import React from 'preact/compat';
import { useState, useEffect } from 'preact/compat';
import { usePWAUpdate } from '../utils/usePWAUpdate';
import faviconUrl from '../assets/favicon.svg';

export function Header() {
  const [currentPath, setCurrentPath] = useState('');
  const { updateAvailable, checkForUpdate, installUpdate } = usePWAUpdate();

  useEffect(() => {
    // Get initial path
    setCurrentPath(window.location.pathname);

    // Listen for navigation changes
    const handleLocationChange = () => {
      setCurrentPath(window.location.pathname);
    };

    // Listen for both pushstate and popstate events
    window.addEventListener('popstate', handleLocationChange);
    
    // Override pushState and replaceState to catch programmatic navigation
    const originalPushState = history.pushState;
    const originalReplaceState = history.replaceState;
    
    history.pushState = function(...args) {
      originalPushState.apply(history, args);
      handleLocationChange();
    };
    
    history.replaceState = function(...args) {
      originalReplaceState.apply(history, args);
      handleLocationChange();
    };

    return () => {
      window.removeEventListener('popstate', handleLocationChange);
      history.pushState = originalPushState;
      history.replaceState = originalReplaceState;
    };
  }, []);

  const getLinkClasses = (href: string) => {
    const isActive = currentPath === href;
    return `inline-block pb-0.5 transition-colors duration-200 ${
      isActive
        ? 'text-wgt-fog font-semibold border-b-2 border-wgt-red drop-shadow-[0_0_10px_rgba(196,60,60,0.35)]'
        : 'text-wgt-muted hover:text-wgt-fog'
    }`;
  };

  return (
    <header class="sticky top-0 z-50 border-b border-white/10 bg-wgt-ink/95 backdrop-blur-md shadow-[0_8px_32px_rgba(0,0,0,0.35)]">
      <div class="container mx-auto px-4 py-4">
        <div class="flex flex-col md:flex-row md:justify-between md:items-center">
          <div class="flex items-center gap-3 mb-4 md:mb-0">
            <a href="/" class="flex items-center gap-3 text-2xl text-wgt-fog hover:text-wgt-red-glow transition-colors">
              <img 
                src={faviconUrl} 
                alt="" 
                class="hidden md:block w-8 h-8"
                width="32"
                height="32"
              />
              <span class="font-display tracking-tight">WGT web app</span>
            </a>
          </div>
          
          <div class="flex items-center space-x-6">
            <nav aria-label="Main">
              <ul class="flex space-x-6">
                <li>
                  <a 
                    href="/" 
                    class={getLinkClasses('/')}
                  >
                    Home
                  </a>
                </li>
                <li>
                  <a 
                    href="/schedule" 
                    class={getLinkClasses('/schedule')}
                  >
                    Schedule
                  </a>
                </li>
                <li>
                  <a 
                    href="/favorites" 
                    class={getLinkClasses('/favorites')}
                  >
                    Favorites
                  </a>
                </li>
              </ul>
            </nav>
            
            <button
              type="button"
              onClick={updateAvailable ? installUpdate : checkForUpdate}
              class={`relative p-2 rounded-lg transition-colors ${
                updateAvailable 
                  ? 'bg-wgt-red text-white hover:bg-wgt-red-glow shadow-md ring-1 ring-white/10' 
                  : 'text-wgt-muted hover:text-wgt-fog hover:bg-wgt-slate/80'
              }`}
              title={updateAvailable ? 'Install update' : 'Check for updates'}
            >
              <svg class="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 010 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" clipRule="evenodd" />
              </svg>
              {updateAvailable && (
                <span class="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full w-3 h-3"></span>
              )}
            </button>
          </div>
        </div>
      </div>
    </header>
  );
}