import {useEffect, useState} from 'preact/compat';
import {EventWithDetails, Schedule} from '../models/types';
import {isScheduleLoaded, loadScheduleData} from '../utils/apiUtils';
import {getAllEventsWithDetails, sortEventsByDateTime} from '../utils/dataUtils';
import {EventCard} from '../components/EventCard';
import {SkeletonLoader} from '../components/SkeletonLoader';
import {getCurrentPageUrl, restoreScrollPosition, setupScrollTracking} from '../utils/scrollUtils';
import React from 'preact/compat';
import motifDividerUrl from '../assets/ui/motif-divider.svg';

export function Home() {
  const [_, setSchedule] = useState<Schedule | null>(null);
  const [upcomingEvents, setUpcomingEvents] = useState<EventWithDetails[]>([]);
  const [loading, setLoading] = useState(!isScheduleLoaded());
  const [error, setError] = useState<string | null>(null);
  const [isWelcomeExpanded, setIsWelcomeExpanded] = useState(false);
  
  useEffect(() => {
    // Check if this is the user's first visit
    const hasVisited = localStorage.getItem('wgt-guide-visited');
    if (!hasVisited) {
      setIsWelcomeExpanded(true);
      localStorage.setItem('wgt-guide-visited', 'true');
    }
  }, []);

  // Set up scroll position tracking
  useEffect(() => setupScrollTracking(), []);
  
  useEffect(() => {
    async function fetchData() {
      try {
        const data = await loadScheduleData();
        setSchedule(data);
        
        // Get all events with details
        const allEvents = getAllEventsWithDetails(data);
        
        // Sort events by date and time
        const sortedEvents = sortEventsByDateTime(allEvents);

        // (aka running right now or today)
        const now = new Date();
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const upcomingEventsTemp = sortedEvents.filter(event => {
          const eventDate = new Date(event.date + ' ' + event.startTime);
          // and not running for more then 1 hour
          return eventDate >= today && ((eventDate.getTime() + 1 * 60 * 60 * 1000) >= now.getTime());
        });
        setUpcomingEvents(upcomingEventsTemp.slice(0, 5));
      } catch (err) {
        setError('Failed to load schedule data. Please try again later.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    
    fetchData();
  }, []);

  // Restore scroll position after data is loaded and rendered
  useEffect(() => {
    if (!loading) {
      // Small delay to ensure DOM is fully rendered
      restoreScrollPosition(getCurrentPageUrl(), 300);
    }
  }, [loading]);

  const toggleWelcome = () => {
    setIsWelcomeExpanded(!isWelcomeExpanded);
  };
  
  if (loading) {
    return <SkeletonLoader message="Loading festival data..." showDays={false} itemCount={3} />;
  }
  
  if (error) {
    return (
      <div class="border border-wgt-red/50 bg-wgt-red/15 text-wgt-fog p-4 rounded-xl">
        <h2 class="font-display text-xl mb-2">Error</h2>
        <p>{error}</p>
      </div>
    );
  }
  
  return (
    <div>
      <section class="mb-8">
        <div class="rounded-xl border border-white/6 bg-wgt-slate/25 backdrop-blur-sm shadow-[0_8px_32px_rgba(0,0,0,0.28)]">
          <div class="p-4 md:p-5">
            <div
              class="cursor-pointer flex items-center justify-between gap-3 rounded-lg w-full min-h-11 transition-colors hover:bg-white/4 focus:outline-none focus-visible:ring-2 focus-visible:ring-wgt-purple/30 focus-visible:ring-offset-2 focus-visible:ring-offset-wgt-slate/30"
              onClick={toggleWelcome}
              role="button"
              tabIndex={0}
              aria-expanded={isWelcomeExpanded}
              onKeyDown={(e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault();
                  toggleWelcome();
                }
              }}
            >
              <h1 class="text-lg md:text-xl font-semibold text-wgt-fog/90 tracking-tight leading-snug">
                Welcome to WGT web app
              </h1>
              <div class="shrink-0 text-wgt-muted" aria-hidden>
                <svg
                  class={`w-5 h-5 transform transition-transform duration-300 ${isWelcomeExpanded ? 'rotate-180' : ''}`}
                  fill="none"
                  stroke="currentColor"
                  strokeWidth={2}
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                </svg>
              </div>
            </div>
            <div
              id="welcome-panel"
              class={`transition-all duration-300 ease-in-out overflow-hidden ${isWelcomeExpanded ? 'max-h-96 opacity-100 mt-3' : 'max-h-0 opacity-0 mt-0'}`}
            >
              <div>
                <p class="text-sm md:text-base text-wgt-muted/95 mb-5 leading-relaxed">
                  Your personal guide to the Wave-Gotik-Treffen festival. Browse the schedule,
                  mark your favorite bands, and create your personalized festival plan.
                </p>
                <div class="flex flex-col sm:flex-row gap-3">
                  <a href="/schedule" class="btn btn-primary text-center text-sm md:text-base py-2.5">
                    View Full Schedule
                  </a>
                  <a href="/favorites" class="btn btn-secondary text-center text-sm md:text-base py-2.5">
                    My Favorites
                  </a>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
      
      <section class="mb-10">
        <h2 class="font-display text-2xl md:text-3xl mb-4 text-wgt-fog">Upcoming Events</h2>
        {upcomingEvents.length > 0 ? (
          <div>
            {upcomingEvents.map(event => (
              <EventCard key={event.id} event={event} sourceInfo={{ name: "Home" }} />
            ))}
            <div class="text-center mt-6">
              <a href="/schedule" class="btn btn-primary">
                View All Events
              </a>
            </div>
          </div>
        ) : (
          <p class="text-wgt-muted">No upcoming events found.</p>
        )}
      </section>

      <div class="flex justify-center text-wgt-purple my-6" aria-hidden>
        <img src={motifDividerUrl} alt="" class="w-48 md:w-64 h-auto opacity-70" width="240" height="16" />
      </div>
      
      <section>
        <h2 class="font-display text-2xl md:text-3xl mb-4 text-wgt-fog">About Wave-Gotik-Treffen</h2>
        <div class="card">
          <p class="mb-4">
            Wave-Gotik-Treffen (WGT) is one of the largest gothic festivals in the world, 
            held annually in Leipzig, Germany. The festival features a diverse range of 
            music styles including gothic rock, EBM, industrial, noise, darkwave, 
            neofolk, neoclassical, and various other genres.
          </p>
          <p>
            <a 
              href="https://www.wave-gotik-treffen.de/" 
              target="_blank" 
              rel="noopener noreferrer"
              class="text-wgt-red-glow hover:text-wgt-fog underline-offset-2 hover:underline"
            >
              Visit the official WGT website →
            </a>
          </p>
        </div>
      </section>
    </div>
  );
}