/**
 * Utility functions for managing scroll position restoration
 */

const SCROLL_POSITIONS_KEY = 'wgt-scroll-positions';

interface ScrollPosition {
  x: number;
  y: number;
  timestamp: number;
}

interface ScrollPositions {
  [url: string]: ScrollPosition;
}

// Debounce function for scroll events
function debounce<T extends (...args: any[]) => void>(func: T, wait: number): T {
  let timeout: NodeJS.Timeout;
  return ((...args: any[]) => {
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(null, args), wait);
  }) as T;
}

/**
 * Get all stored scroll positions
 */
function getStoredScrollPositions(): ScrollPositions {
  try {
    const stored = sessionStorage.getItem(SCROLL_POSITIONS_KEY);
    return stored ? JSON.parse(stored) : {};
  } catch (error) {
    console.warn('Failed to load scroll positions:', error);
    return {};
  }
}

/**
 * Save scroll positions to session storage
 */
function saveScrollPositions(positions: ScrollPositions): void {
  try {
    sessionStorage.setItem(SCROLL_POSITIONS_KEY, JSON.stringify(positions));
  } catch (error) {
    console.warn('Failed to save scroll positions:', error);
  }
}

/**
 * Store the current scroll position for a given URL
 */
export function storeScrollPosition(url: string): void {
  const positions = getStoredScrollPositions();
  
  positions[url] = {
    x: window.scrollX,
    y: window.scrollY,
    timestamp: Date.now()
  };
  
  saveScrollPositions(positions);
}

/**
 * Restore scroll position for a given URL
 */
export function restoreScrollPosition(url: string, delay: number = 0): void {
  const positions = getStoredScrollPositions();
  const position = positions[url];
  
  if (position) {
    // Clean up old positions (older than 1 hour)
    const oneHourAgo = Date.now() - (60 * 60 * 1000);
    if (position.timestamp < oneHourAgo) {
      delete positions[url];
      saveScrollPositions(positions);
      return;
    }
    
    // Restore scroll position
    const restore = () => {
      window.scrollTo(position.x, position.y);
    };
    
    if (delay > 0) {
      setTimeout(restore, delay);
    } else {
      restore();
    }
  }
}

/**
 * Clear stored scroll position for a given URL
 */
export function clearScrollPosition(url: string): void {
  const positions = getStoredScrollPositions();
  delete positions[url];
  saveScrollPositions(positions);
}

/**
 * Clear all stored scroll positions
 */
export function clearAllScrollPositions(): void {
  try {
    sessionStorage.removeItem(SCROLL_POSITIONS_KEY);
  } catch (error) {
    console.warn('Failed to clear scroll positions:', error);
  }
}

/**
 * Reset scroll position to 0.
 */
export function resetScrollPosition(delay: number = 0): void {
  if (delay > 0) {
    setTimeout(() => {
      window.scrollTo(0, 0);
    }, delay);
  } else {
    window.scrollTo(0, 0);
  }
}


/**
 * Set up automatic scroll position tracking for the current page
 * Returns a cleanup function to remove the event listener
 */
export function setupScrollTracking(): () => void {
  const currentUrl = getCurrentPageUrl();
  
  // Debounced function to store scroll position
  const debouncedStore = debounce(() => {
    storeScrollPosition(currentUrl);
  }, 150); // Store position 150ms after scrolling stops
  
  // Add scroll event listener
  window.addEventListener('scroll', debouncedStore, { passive: true });
  
  // Return cleanup function
  return () => {
    window.removeEventListener('scroll', debouncedStore);
  };
}

/**
 * Get the current page URL for scroll position tracking
 */
export function getCurrentPageUrl(): string {
  return window.location.pathname + window.location.search;
} 