import React, { useState, useRef, useEffect } from 'preact/compat';
import { Router } from 'preact-router';
import '../styles/transition.css';

/** Must match animation duration in `src/styles/transition.css`. */
const ROUTE_TRANSITION_MS = 300;

interface TransitionRouterProps {
  children: React.ReactNode;
}

function removePrevPageSnapshot(container: HTMLDivElement | null) {
  container?.querySelector('.prev-page')?.remove();
}

export function TransitionRouter({ children }: TransitionRouterProps) {
  const [currentUrl, setCurrentUrl] = useState<string>(typeof window !== 'undefined' ? window.location.pathname : '/');
  const [isTransitioning, setIsTransitioning] = useState<boolean>(false);
  const [isBackNavigation, setIsBackNavigation] = useState<boolean>(false);
  const routerRef = useRef<HTMLDivElement>(null);
  const routerContentRef = useRef<HTMLDivElement>(null);
  const urlHistoryRef = useRef<string[]>([]);

  // Create a snapshot of the current page before transitioning
  const createPageSnapshot = () => {
    if (routerContentRef.current) {
      // Create a deep clone of the current content
      const clone = routerContentRef.current.cloneNode(true) as HTMLElement;
      clone.classList.add('prev-page');
      clone.classList.remove('current-page');
      return clone;
    }
    return null;
  };

  // Initialize URL history on mount
  useEffect(() => {
    if (typeof window !== 'undefined') {
      urlHistoryRef.current = [window.location.pathname];
    }
  }, []);

  // Handle route changes
  const handleRouteChange = (e: { url: string }) => {
    if (e.url !== currentUrl) {
      // Take a snapshot of the current page before it changes
      const snapshot = createPageSnapshot();

      // Check if this is a back navigation
      const history = urlHistoryRef.current;
      const isBack = history.length > 1 && history[history.length - 2] === e.url;

      if (isBack) {
        // This is a back navigation, remove the current URL from history
        urlHistoryRef.current = history.slice(0, -1);
        setIsBackNavigation(true);
      } else {
        // This is a forward navigation, add the new URL to history
        urlHistoryRef.current = [...history, e.url];
        setIsBackNavigation(false);
      }

      // Update current URL and trigger transition
      setCurrentUrl(e.url);

      // Add the previous content to the DOM
      if (routerRef.current && snapshot) {
        // If there's already a previous page, remove it first
        removePrevPageSnapshot(routerRef.current);
        routerRef.current.appendChild(snapshot);
      }

      setIsTransitioning(true);
    }
  };

  /* Tear down the snapshot only after CSS animations finish. Removing early or
   * clearing `.transitioning` before removal can make Safari briefly apply the
   * snapshot’s reset styles (one “blip” of the old page). */
  useEffect(() => {
    if (!isTransitioning) return;

    const timer = window.setTimeout(() => {
      removePrevPageSnapshot(routerRef.current);
      setIsTransitioning(false);
    }, ROUTE_TRANSITION_MS);

    return () => clearTimeout(timer);
  }, [isTransitioning]);

  return (
    <div 
      ref={routerRef}
      className={
      `router-container
       ${isTransitioning ? 'transitioning' : ''} 
       ${isBackNavigation ? 'back-navigation' : 'forward-navigation'}
       min-h-screen`
      }
    >
      <div ref={routerContentRef} className="current-page">
        <Router onChange={handleRouteChange}>
          {children}
        </Router>
      </div>
    </div>
  );
}

