import React from 'preact/compat';
import { route } from 'preact-router';
import { EventWithDetails } from '../models/types';
import { isFavorite, addFavorite, removeFavorite, getCountryFlag } from '../utils/dataUtils';
import { useState } from 'preact/compat';

interface EventCardProps {
  event: EventWithDetails;
  showFavoriteButton?: boolean;
  sourceInfo?: { name: string };
  clickable?: boolean;
}

export function EventCard({ event, showFavoriteButton = true, clickable = true, sourceInfo }: EventCardProps) {
  const [isFav, setIsFav] = useState(isFavorite(event.id));
  
  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric'
    });
  };
  
  const handleFavoriteToggle = (e: Event) => {
    e.stopPropagation(); // Prevent navigation when clicking favorite button
    if (isFav) {
      removeFavorite(event.id);
      setIsFav(false);
    } else {
      addFavorite(event.id);
      setIsFav(true);
    }
  };

  const handleCardClick = () => {
    let url = `/band/${event.band.id}`;
    if (sourceInfo) {
      const params = new URLSearchParams({
        fromName: sourceInfo.name
      });
      url += `?${params.toString()}`;
    }
    route(url);
  };

  const handleKeyDown = (e: KeyboardEvent) => {
    if (!clickable) return;
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleCardClick();
    }
  };
  
  return (
    <div 
      class={`card mb-2 md:mb-4 ${clickable ? 'cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wgt-red/70 focus-visible:ring-offset-2 focus-visible:ring-offset-wgt-void' : ''}`}
      onClick={clickable ? handleCardClick : undefined}
      onKeyDown={clickable ? handleKeyDown : undefined}
      role={clickable ? 'button' : undefined}
      tabIndex={clickable ? 0 : undefined}
    >
      <div class="flex justify-between items-start">
        <div class="flex-1 min-w-0 mr-2">
          <h3 class="text-l md:text-xl font-semibold text-white">
            {event.band.name}
            {event.band.country && (
              <span class="ml-2" title={`Country: ${event.band.country}`}>
                {getCountryFlag(event.band.country)}
              </span>
            )}
          </h3>
          {(event.band.genre || event.band.description) && (
            <p class="text-sm text-wgt-muted truncate">{event.band.genre}{event.band.description && `${event.band.genre ? ' - ' : ''} ${event.band.description}`}</p>
          )}
        </div>
        {showFavoriteButton && (
          <button 
            onClick={handleFavoriteToggle}
            class={`favorite-icon text-l md:text-2xl ${isFav ? 'active' : ''}`}
            aria-label={isFav ? 'Remove from favorites' : 'Add to favorites'}
          >
            {isFav ? '★' : '☆'}
          </button>
        )}
      </div>
      
      <div class="text-sm md:text-base mt-1 md:mt-3 text-gray-300">
        <p class="flex items-center">
          <span class="inline-block w-20 text-wgt-muted">Date:</span>
          {formatDate(event.date)}
        </p>
        <p class="flex items-center">
          <span class="inline-block w-20 text-wgt-muted">Time:</span>
          {event.startTime}{event.endTime ? ` - ${event.endTime}` : ''}
        </p>
        <p class="flex items-center">
          <span class="inline-block w-20 text-wgt-muted">Venue:</span>
          <span class="truncate md:overflow-visible">{event.location.name}</span>
        </p>
        {event.location.address && (
            <p class="text-sm text-wgt-muted/80 ml-20">
            {event.location.address}, {event.location.city}
          </p>
        )}
      </div>
    </div>
  );
}