import React, { useState, useEffect } from 'preact/compat';
import { Link } from 'preact-router/match';
import { Schedule, Band, EventWithDetails } from '../models/types';
import { loadScheduleData, isScheduleLoaded } from '../utils/apiUtils';
import { findBandById, findEventsByBandId, sortEventsByDateTime } from '../utils/dataUtils';
import { EventCard } from '../components/EventCard';
import { SkeletonLoader } from '../components/SkeletonLoader';
import { resetScrollPosition } from '../utils/scrollUtils';

interface BandDetailProps {
  id: string;
  fromName?: string;
}

export function BandDetail({ id, fromName }: BandDetailProps) {
  const [schedule, setSchedule] = useState<Schedule | null>(null);
  const [band, setBand] = useState<Band | null>(null);
  const [events, setEvents] = useState<EventWithDetails[]>([]);
  const [loading, setLoading] = useState(!isScheduleLoaded());
  const [error, setError] = useState<string | null>(null);
  
  // Use passed parameters or default to Schedule
  const backLink = {
    name: fromName ? decodeURIComponent(fromName) : 'Schedule'
  };

  const handleBackClick = () => {
    // Navigate to the back URL
    window.history.back();
  };
  
  useEffect(() => {
    async function fetchData() {
      try {
        const data = await loadScheduleData();
        setSchedule(data);
        
        // Find the band by ID
        const bandData = findBandById(id, data);
        if (!bandData) {
          setError('Band not found');
          setLoading(false);
          return;
        }
        
        setBand(bandData);
        
        // Find events for this band
        const bandEvents = findEventsByBandId(id, data);
        setEvents(sortEventsByDateTime(bandEvents));
      } catch (err) {
        setError('Failed to load band data. Please try again later.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    
    fetchData();
  }, [id]);

  // Reset scroll position to 0
  useEffect(() => {
    if (!loading) {
      // Small delay to ensure DOM is fully rendered
      resetScrollPosition(300);
    }
  }, [loading]);
  
  if (loading) {
    return <SkeletonLoader message="Loading band information..." showDays={false} itemCount={2} />;
  }
  
  if (error || !band) {
    return (
      <div class="border border-wgt-red/50 bg-wgt-red/15 text-wgt-fog p-4 rounded-xl">
        <h2 class="font-display text-xl mb-2">Error</h2>
        <p>{error || 'Band not found'}</p>
        <button onClick={handleBackClick} class="btn btn-primary mt-4">
          Back to {backLink.name}
        </button>
      </div>
    );
  }
  
  return (
    <div>
      <button type="button" onClick={handleBackClick} class="text-wgt-muted hover:text-wgt-fog mb-4 inline-block bg-transparent border-none cursor-pointer">
        ← Back to {backLink.name}
      </button>
      
      <div class="card mb-6">
        <h1 class="font-display text-3xl md:text-4xl text-wgt-fog mb-2">{band.name}</h1>
        
        {band.genre && (
          <p class="text-wgt-muted mb-4">{band.genre}</p>
        )}
        
        {band.description && (
          <div class="mt-4">
            <h2 class="font-display text-xl mb-2">About</h2>
            <p class="text-wgt-fog/90 leading-relaxed">{band.description}</p>
          </div>
        )}
      </div>
      
      <div class="mt-8">
        <h2 class="font-display text-2xl md:text-3xl mb-4 text-wgt-fog">Performances</h2>
        
        {events.length > 0 ? (
          <div>
            {events.map(event => (
              <EventCard key={event.id} event={event} sourceInfo={{ name: `${band.name} Details`}} clickable={false} />
            ))}
          </div>
        ) : (
          <div class="card text-center py-8">
            <p class="text-xl text-wgt-muted">No performances scheduled for this band.</p>
          </div>
        )}
      </div>
      
      {/* Copyright notice for band descriptions */}
      {band.description && (
        <div class="mt-8 pt-4 border-t border-white/10">
          <p class="text-xs text-wgt-muted text-center">
            Band description sourced from{' '}
            <a 
              href="https://www.discogs.com" 
              target="_blank" 
              rel="noopener noreferrer"
              class="text-wgt-fog/80 hover:text-wgt-fog underline"
            >
              Discogs.com
            </a>
          </p>
        </div>
      )}
    </div>
  );
}