import React from 'preact/compat';
import {Route} from 'preact-router';

import {Header} from './Header';
import {Footer} from './Footer';
import {PWAUpdateNotifier} from './PWAUpdateNotifier';
import {SkeletonApp} from './SkeletonLoader';
import {TransitionRouter} from './TransitionRouter';
import {Home} from '../pages/Home';
import {Schedule} from '../pages/Schedule';
import {Favorites} from '../pages/Favorites';
import {BandDetail} from '../pages/BandDetail';
import {SharedSchedule} from '../pages/SharedSchedule';
import {Impressum} from '../pages/Impressum';
import {NotFound} from '../pages/NotFound';

export function App() {

    return (
        <div class="app-shell relative z-[1] min-h-screen flex flex-col">
            <Header/>
            <main class="flex-grow container mx-auto px-4 py-8">
                <TransitionRouter>
                    <Route path="/" component={Home}/>
                    <Route path="/schedule" component={Schedule}/>
                    <Route path="/favorites" component={Favorites}/>
                    <Route path="/band/:id" component={BandDetail}/>
                    <Route path="/shared" component={SharedSchedule}/>
                    <Route path="/impressum" component={Impressum}/>
                    <Route default component={NotFound}/>
                </TransitionRouter>
            </main>
            <Footer/>
            <PWAUpdateNotifier/>
        </div>
    );
}
